import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.DEqXEGcv.js";const p=JSON.parse('{"title":"What is RDE","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/guide/what-is-rde.md","filePath":"en/docs/guide/what-is-rde.md"}'),n={name:"en/docs/guide/what-is-rde.md"};function o(s,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="what-is-rde" tabindex="-1">What is RDE <a class="header-anchor" href="#what-is-rde" aria-label="Permalink to &quot;What is RDE&quot;">​</a></h1><p><strong>RDE</strong> (Ruizi Desktop Environment) is an open-source web desktop environment that turns Linux servers into feature-rich cloud desktops. Access a Windows-like experience through your browser, with file management, Docker apps, system monitoring, and more.</p><h2 id="why-rde" tabindex="-1">Why RDE? <a class="header-anchor" href="#why-rde" aria-label="Permalink to &quot;Why RDE?&quot;">​</a></h2><ul><li><strong>No desktop environment needed</strong>: No GNOME/KDE overhead — operate via the web</li><li><strong>Access anywhere</strong>: Open in any browser — phone, tablet, or desktop</li><li><strong>Feature-rich</strong>: File manager, Docker app store, media playback, download manager, and more</li><li><strong>Free &amp; open source</strong>: All core features are free, licensed under GPL-3.0</li></ul><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h2><h3 id="🖥️-web-desktop-experience" tabindex="-1">🖥️ Web Desktop Experience <a class="header-anchor" href="#🖥️-web-desktop-experience" aria-label="Permalink to &quot;🖥️ Web Desktop Experience&quot;">​</a></h3><p>A Windows-like window manager with drag, resize, maximize, minimize, taskbar, and context menus. Supports iframe, component, and popup window types for a true desktop feel in the browser.</p><h3 id="📁-file-management" tabindex="-1">📁 File Management <a class="header-anchor" href="#📁-file-management" aria-label="Permalink to &quot;📁 File Management&quot;">​</a></h3><p>A full-featured file manager with upload, download, preview, and sharing. Large files use TUS protocol for resumable uploads supporting 10GB+ files.</p><h3 id="🐳-docker-app-store" tabindex="-1">🐳 Docker App Store <a class="header-anchor" href="#🐳-docker-app-store" aria-label="Permalink to &quot;🐳 Docker App Store&quot;">​</a></h3><p>Visually manage Docker containers and images. One-click deploy common applications without memorizing complex command-line arguments.</p><h3 id="💻-web-terminal" tabindex="-1">💻 Web Terminal <a class="header-anchor" href="#💻-web-terminal" aria-label="Permalink to &quot;💻 Web Terminal&quot;">​</a></h3><p>A web terminal built on xterm.js + WebSocket + PTY. Full Linux Shell in the browser with multi-session management and theme switching.</p><h3 id="📦-more-built-in-apps" tabindex="-1">📦 More Built-in Apps <a class="header-anchor" href="#📦-more-built-in-apps" aria-label="Permalink to &quot;📦 More Built-in Apps&quot;">​</a></h3><ul><li><strong>Download Manager</strong>: Aria2-based, supports HTTP/BT/magnet links</li><li><strong>Music Player</strong>: Lyrics display, audio visualization, multiple play modes</li><li><strong>Video Player</strong>: Multi-format playback, ffmpeg live HLS transcoding</li><li><strong>Photos</strong>: Photo metadata extraction, thumbnail generation, Synology-like experience</li><li><strong>Retro Games</strong>: WebAssembly emulator for NES/SNES/GBA/PS1 and more</li><li><strong>Flatpak Apps</strong>: Run Linux GUI apps in the browser</li></ul><h3 id="🔌-plugin-system" tabindex="-1">🔌 Plugin System <a class="header-anchor" href="#🔌-plugin-system" aria-label="Permalink to &quot;🔌 Plugin System&quot;">​</a></h3><p>A plugin mechanism using Unix Socket HTTP communication with hot-swappable loading to easily extend functionality.</p><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th></tr></thead><tbody><tr><td>Backend</td><td>Go, Gin, GORM, SQLite</td></tr><tr><td>Frontend</td><td>Svelte 5, SvelteKit, Tailwind CSS v4, Vite</td></tr><tr><td>Containers</td><td>Docker API</td></tr><tr><td>Downloads</td><td>Aria2 RPC</td></tr><tr><td>Plugins</td><td>Unix Socket HTTP</td></tr></tbody></table><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><pre><code>Browser → RDE Server (Go + SQLite)
          ├── Desktop Environment (SvelteKit)
          │   ├── Window Manager
          │   ├── Taskbar
          │   └── App UI
          ├── Feature Modules
          │   ├── File Management
          │   ├── Docker Management
          │   ├── Terminal Service
          │   ├── Download Manager
          │   └── Backup &amp; Restore
          └── Plugin System
</code></pre><h2 id="premium-services" tabindex="-1">Premium Services <a class="header-anchor" href="#premium-services" aria-label="Permalink to &quot;Premium Services&quot;">​</a></h2><p>All open-source features of RDE are free forever. Optional paid premium services include:</p><ul><li><strong>Docker Mirror Acceleration</strong>: Built-in registry reverse proxy for faster image pulls in China</li><li><strong>Cloud Backup</strong>: Automatic backup of system config and user data to the cloud</li><li><strong>AI Assistant</strong>: DeepSeek-powered intelligent chat</li><li><strong>Android Emulator</strong>: Run Android apps in the cloud desktop</li><li><strong>Virtual Machines</strong>: QEMU/KVM virtual machine management</li></ul><p>See <a href="/shop.html">Membership Plans</a> for details.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/en/docs/guide/getting-started.html">Quick Start</a> — Install and get running in 5 minutes</li><li><a href="/en/docs/guide/installation.html">Installation</a> — Detailed deployment guide</li></ul>`,27)])])}const m=t(n,[["render",o]]);export{p as __pageData,m as default};
